#include<bits/stdc++.h>
using namespace std;
vector<long long> e[500010],s[500010];
long long a[500010],b[500010],n;
int main()
{
    scanf("%lld",&n);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&a[i]);
    }
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&b[i]);
    }
    long long ans=0;
    for(long long i=1;i<=n;i++)
    {
        if(a[i]==b[i])
        {
            ans+=1ll*i*(i-1)/2+1ll*(n-i)*(n-i+1)/2;
        }
        e[i].push_back(0);
        s[i].push_back(0);
    }
    for(long long i=1;i<=n;i++)
    {
        e[b[i]].push_back(i);
        s[b[i]].push_back(s[b[i]].back()+i);
        if(e[a[i]].back()!=0)
        {
            long long line=min(i,n-i+1);
            long long pos=lower_bound(e[a[i]].begin(),e[a[i]].end(),line)-e[a[i]].begin()-1;
            ans+=s[a[i]][pos]+line*(e[a[i]].size()-(pos+1));
        }
    }
    for(long long i=1;i<=n;i++)
    {
        s[i].clear();
        e[i].clear();
        s[i].push_back(0);
        e[i].push_back(0);
    }
    reverse(a+1,a+1+n);
    reverse(b+1,b+1+n);
    for(long long i=1;i<=n;i++)
    {
        if(e[a[i]].back()!=0)
        {
            long long line=min(i,n-i+1);
            long long pos=lower_bound(e[a[i]].begin(),e[a[i]].end(),line)-e[a[i]].begin()-1;
            ans+=s[a[i]][pos]+line*(e[a[i]].size()-(pos+1));
        }
        e[b[i]].push_back(i);
        s[b[i]].push_back(s[b[i]].back()+(i));
    }
    printf("%lld",ans);
    return 0;
}
